class Dog(val name: String) {
    var energy = 10

    // Member Function
    fun bark() {
        println("$name says: WOOF!")
        energy -= 1
    }
}

fun main() {
    val fido = Dog("Fido")
    // Using Dot Notation to trigger the action
    fido.bark() 
    println("Energy is now ${fido.energy}")
}
